      "vi": "Quan thoại Hợp Phì (Giang Hoài)",
      "th": "ภาษาจีนกลางเหอเฝย (เจียงหวาย)",
      "id": "Mandarin Hefei (Jianghuai)",
      "hi": "हेफ़ेई मंदारिन (जियांगहुआई)",
      "de": "Hefei-Mandarin (Jianghuai)",
      "fr": "Mandarin de Hefei (Jianghuai)",
      "it": "Mandarino di Hefei (Jianghuai)",
      "es": "Mandarín de Hefei (Jianghuái)",
      "pt": "Mandarim de Hefei (Jianghuai)",
