      "en": "Nanjing Mandarin",
      "yue": "南京官話",
      "vi": "Quan thoại Nam Kinh",
      "th": "ภาษาจีนกลางหนานจิง",
      "id": "Mandarin Nanjing",
      "hi": "नानजिंग मंदारिन",
