      "vi": "Tiếng Triều Châu (Chaozhou)",
      "th": "ภาษาแต้จิ๋ว (เฉาโจว)",
      "id": "Teochew (Chaozhou)",
      "hi": "तेओचेव (चाओझोउ)",
      "de": "Teochew (Chaozhou-Min-Nan)",
      "fr": "Teochew (min nan du Chaozhou)",
      "it": "Teochew (Chaozhou)",
      "es": "Teochew (Chaozhou)",
      "pt": "Teochew (Chaozhou)",
      "ru": "Теочью (Чаочжоу)",
      "uk": "Теочью (Чаочжоу)",
