      "vi": "Mông Cổ nguyên thủy (tái dựng)",
      "th": "ภาษามองโกลดั้งเดิม (การสร้างใหม่)",
      "id": "Proto-Mongolik (rekonstruksi)",
      "hi": "आद्य-मंगोलिक (पुनर्निर्माण)",
      "de": "Urmongolisch (Rekonstruktion)",
      "fr": "Proto-mongol (reconstruction)",
      "it": "Proto-mongolico (ricostruzione)",
      "es": "Protomongólico (reconstrucción)",
      "pt": "Protomongólico (reconstrução)",
      "ru": "Прамонгольский (реконструкция)",
